#include <stdio.h>

void print_binary(unsigned int n, int bits) {
    for (int i = bits - 1; i >= 0; i--) {
        printf("%d", (n >> i) & 1);
    }
    printf("\n");
}

int main() {
    unsigned int num = 11;

    printf("Decimal: %u\n", num);
    printf("Binary (8-bit): ");
    print_binary(num, 8);  // Output: 00001011

    printf("\nBinary of 255: ");
    print_binary(255, 8);  // Output: 11111111

    return 0;
}

public class BitCounter {
    // Method 1: Using loop
    public static int countBits(int n) {
        int count = 0;
        while (n > 0) {
            count += n & 1;  // Add LSB to count
            n >>= 1;          // Right shift
        }
        return count;
    }

    // Method 2: Brian Kernighan's Algorithm
    public static int countBitsFast(int n) {
        int count = 0;
        while (n > 0) {
            n = n & (n - 1);  // Clears rightmost set bit
            count++;
        }
        return count;
    }

    public static void main(String[] args) {
        System.out.println(countBits(11));      // 3 (1011 has three 1s)
        System.out.println(countBits(255));     // 8 (11111111)
        System.out.println(Integer.bitCount(11)); // Built-in: 3
    }
}

module binary_example;
    // Binary number declarations
    reg [7:0] byte_val;      // 8-bit register
    reg [3:0] nibble_val;    // 4-bit register

    initial begin
        // Different ways to assign binary values
        byte_val = 8'b10110101;    // Binary literal
        nibble_val = 4'd11;        // Decimal 11 = 1011

        $display("Byte: %b = %d", byte_val, byte_val);
        $display("Nibble: %b = %d", nibble_val, nibble_val);

        // Bit selection
        $display("MSB of byte: %b", byte_val[7]);
        $display("LSB of byte: %b", byte_val[0]);
        $display("Upper nibble: %b", byte_val[7:4]);
    end
endmodule
